{"rawEvent":{"message_id":"019daded4e0b7d3db4c638e4ae1a5424","conversation_id":"019dade4fd787ac38bd21ac6ab930e5b","tool_call_id":"tooluse_FZR8YIBvLRGO6WJbMSb1Al","document":{"file_path":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","sub_content":"AmapClient.java","sub_content_event":"open_editor","sub_content_event_value":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","sub_content_tip":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","apply_content":"package org.example;

import com.alibaba.fastjson2.JSON;
import com.alibaba.fastjson2.JSONObject;
import okhttp3.HttpUrl;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

/**
 * 高德地图 Web 服务 API 客户端
 * <p>
 * 封装了三个常用功能：
 * <ul>
 *     <li>POI 搜索：根据关键词查询地点</li>
 *     <li>天气查询：根据城市 adcode 查询实时天气</li>
 *     <li>路径规划：驾车导航路线规划</li>
 * </ul>
 * <p>
 * 使用前请到 https://lbs.amap.com/ 申请 "Web 服务" 类型的 Key
 */
public class AmapClient {

    /** 高德 Web 服务 API 的基础地址 */
    private static final String BASE_URL = "https://restapi.amap.com/v3";

    /** TODO: 替换成你在高德开放平台申请的 Key */
    private final String apiKey;

    /** OkHttp 客户端（复用连接池，提升性能） */
    private final OkHttpClient httpClient;

    public AmapClient(String apiKey) {
        this.apiKey = apiKey;
        this.httpClient = new OkHttpClient.Builder()
                .connectTimeout(5, TimeUnit.SECONDS)
                .readTimeout(10, TimeUnit.SECONDS)
                .build();
    }

    // =====================================================================
    // 1. POI 搜索
    // 文档：https://lbs.amap.com/api/webservice/guide/api/search
    // =====================================================================

    /**
     * POI 关键词搜索
     *
     * @param keywords 搜索关键词，如 "肯德基"、"北京大学"
     * @param city     城市名或 adcode，如 "北京"、"010"，传 null 则全国搜索
     * @return 原始 JSON 响应（包含 pois 列表）
     */
    public JSONObject searchPoi(String keywords, String city) throws IOException {
        HttpUrl.Builder urlBuilder = HttpUrl.parse(BASE_URL + "/place/text").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("keywords", keywords)
                .addQueryParameter("offset", "10")   // 每页条数
                .addQueryParameter("page", "1")
                .addQueryParameter("extensions", "base");
        if (city != null && !city.isEmpty()) {
            urlBuilder.addQueryParameter("city", city);
        }
        return doGet(urlBuilder.build().toString());
    }

    // =====================================================================
    // 2. 天气查询
    // 文档：https://lbs.amap.com/api/webservice/guide/api/weatherinfo
    // =====================================================================

    /**
     * 查询指定城市的天气
     *
     * @param adcode     城市编码，如 "110000"（北京）、"440100"（广州）
     * @param isForecast true 查询未来 3 天预报；false 查询实时天气
     * @return 原始 JSON 响应
     */
    public JSONObject queryWeather(String adcode, boolean isForecast) throws IOException {
        String url = HttpUrl.parse(BASE_URL + "/weather/weatherInfo").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("city", adcode)
                .addQueryParameter("extensions", isForecast ? "all" : "base")
                .build().toString();
        return doGet(url);
    }

    // =====================================================================
    // 3. 路径规划（驾车）
    // 文档：https://lbs.amap.com/api/webservice/guide/api/direction
    // =====================================================================

    /**
     * 驾车路径规划
     *
     * @param origin      起点经纬度，格式 "经度,纬度"，如 "116.481028,39.989643"
     * @param destination 终点经纬度，格式同上
     * @return 原始 JSON 响应（包含 route.paths 路线数组）
     */
    public JSONObject drivingRoute(String origin, String destination) throws IOException {
        String url = HttpUrl.parse(BASE_URL + "/direction/driving").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("origin", origin)
                .addQueryParameter("destination", destination)
                .addQueryParameter("extensions", "base")
                .addQueryParameter("strategy", "0")   // 0=速度优先
                .build().toString();
        return doGet(url);
    }

    // =====================================================================
    // 通用 GET 请求
    // =====================================================================

    private JSONObject doGet(String url) throws IOException {
        Request request = new Request.Builder()
                .url(url)
                .get()
                .build();

        try (Response response = httpClient.newCall(request).execute()) {
            if (!response.isSuccessful() || response.body() == null) {
                throw new IOException("请求失败，HTTP 状态码: " + response.code());
            }
            String body = response.body().string();
            return JSON.parseObject(body);
        }
    }
}
