    // 1. POI 搜索
    // 文档：https://lbs.amap.com/api/webservice/guide/api/search
    // =====================================================================

    /**
     * POI 关键词搜索
     *
     * @param keywords 搜索关键词，如 "肯德基"、"北京大学"
     * @param city     城市名或 adcode，如 "北京"、"010"，传 null 则全国搜索
