package org.example;

import com.alibaba.fastjson2.JSONObject;

/**
 * 高德地图 API 调用示例
 */
public class Main {

    /** TODO: 在这里填入你申请的高德 Web 服务 Key */
    private static final String AMAP_KEY = "59d11d17908c9a5ddc8176d78700d6df";

    public static void main(String[] args) {
        AmapClient client = new AmapClient(AMAP_KEY);

        try {
            // ========== 1. POI 搜索：在上海搜索 "肯德基" ==========
            System.out.println("========== POI 搜索 ==========");
            JSONObject poiResult = client.searchPoi("肯德基", "上海");
            System.out.println("状态: " + poiResult.getString("status")
                    + "，共找到: " + poiResult.getString("count") + " 条");
            // 打印前 3 条结果的名称和地址
            poiResult.getJSONArray("pois").stream().limit(3).forEach(poi -> {
                JSONObject p = (JSONObject) poi;
                System.out.println("  - " + p.getString("name") + " @ " + p.getString("address"));
            });

            // ========== 2. 天气查询：北京实时天气 ==========
            System.out.println("\n========== 天气查询 ==========");
            JSONObject weatherResult = client.queryWeather("110000", false);
            JSONObject live = weatherResult.getJSONArray("lives").getJSONObject(0);
            System.out.println("城市: " + live.getString("city")
                    + "，天气: " + live.getString("weather")
                    + "，温度: " + live.getString("temperature") + "℃"
                    + "，风向: " + live.getString("winddirection"));

            // ========== 3. 路径规划：从天安门到故宫的驾车路线 ==========
            System.out.println("\n========== 驾车路径规划 ==========");
            JSONObject routeResult = client.drivingRoute(
                    "116.397428,39.909230",   // 天安门
                    "116.403963,39.915119"    // 故宫
            );
            JSONObject path = routeResult.getJSONObject("route")
                    .getJSONArray("paths").getJSONObject(0);
            System.out.println("总距离: " + path.getString("distance") + " 米");
            System.out.println("预计耗时: " + path.getString("duration") + " 秒");

        } catch (Exception e) {
            System.err.println("调用高德 API 出错: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

