{"rawEvent":{"message_id":"019daee88ea37d0994eec59c7826195f","conversation_id":"019dade4fd787ac38bd21ac6ab930e5b","tool_call_id":"tooluse_keAw4hSntWp5SLBTCzW0Dj","document":{"file_path":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/model/Poi.java","sub_content":"Poi.java","sub_content_event":"open_editor","sub_content_event_value":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/model/Poi.java","sub_content_tip":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/model/Poi.java","apply_content":"package org.example.model;

import com.alibaba.fastjson2.annotation.JSONField;

/**
 * POI 搜索结果项
 * <p>
 * 对应高德 `/v3/place/text` 接口返回的 pois 数组中每一项。
 * 文档：https://lbs.amap.com/api/webservice/guide/api/search
