{"rawEvent":{"message_id":"019daee88ea37d0994eec59c7826195f","conversation_id":"019dade4fd787ac38bd21ac6ab930e5b","tool_call_id":"tooluse_WMoKaNO1gDLZw03TUeexPH","document":{"file_path":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","sub_content":"AmapClient.java","sub_content_event":"open_editor","sub_content_event_value":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","sub_content_tip":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/AmapClient.java","apply_content":"package org.example;

import com.alibaba.fastjson2.JSON;
import com.alibaba.fastjson2.JSONArray;
import com.alibaba.fastjson2.JSONObject;
import okhttp3.HttpUrl;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import org.example.model.Poi;
import org.example.model.Route;
import org.example.model.WeatherForecast;
import org.example.model.WeatherLive;

import java.io.IOException;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.TimeUnit;

/**
 * 高德地图 Web 服务 API 客户端
 * <p>
 * 封装了三个常用功能：
 * <ul>
 *     <li>POI 搜索：根据关键词查询地点，返回 {@link Poi} 列表</li>
 *     <li>天气查询：实时 {@link WeatherLive} / 预报 {@link WeatherForecast}</li>
 *     <li>路径规划：驾车导航，返回 {@link Route}</li>
 * </ul>
 * <p>
 * 使用前请到 https://lbs.amap.com/ 申请 "Web 服务" 类型的 Key
 */
public class AmapClient {

    /** 高德 Web 服务 API 的基础地址 */
    private static final String BASE_URL = "https://restapi.amap.com/v3";

    /** 高德返回成功的状态码 */
    private static final String STATUS_OK = "1";

    private final String apiKey;

    /** OkHttp 客户端（复用连接池，提升性能） */
    private final OkHttpClient httpClient;

    public AmapClient(String apiKey) {
        this.apiKey = apiKey;
        this.httpClient = new OkHttpClient.Builder()
                .connectTimeout(5, TimeUnit.SECONDS)
                .readTimeout(10, TimeUnit.SECONDS)
                .build();
    }

    // =====================================================================
    // 1. POI 搜索
    // 文档：https://lbs.amap.com/api/webservice/guide/api/search
    // =====================================================================

    /**
     * POI 关键词搜索
     *
     * @param keywords 搜索关键词，如 "肯德基"、"北京大学"
     * @param city     城市名或 adcode，如 "北京"、"010"，传 null 则全国搜索
     * @return POI 列表（可能为空，但不会为 null）
     */
    public List<Poi> searchPoi(String keywords, String city) throws IOException {
        HttpUrl.Builder urlBuilder = HttpUrl.parse(BASE_URL + "/place/text").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("keywords", keywords)
                .addQueryParameter("offset", "10")
                .addQueryParameter("page", "1")
                .addQueryParameter("extensions", "base");
        if (city != null && !city.isEmpty()) {
            urlBuilder.addQueryParameter("city", city);
        }
        JSONObject json = doGet(urlBuilder.build().toString());
        checkStatus(json, "POI 搜索");

        JSONArray pois = json.getJSONArray("pois");
        if (pois == null || pois.isEmpty()) {
            return Collections.emptyList();
        }
        return pois.toJavaList(Poi.class);
    }

    // =====================================================================
    // 2. 天气查询
    // 文档：https://lbs.amap.com/api/webservice/guide/api/weatherinfo
    // =====================================================================

    /**
     * 查询指定城市的实时天气
     *
     * @param adcode 城市编码，如 "110000"（北京）
     * @return 实时天气，若无数据返回 null
     */
    public WeatherLive queryWeatherLive(String adcode) throws IOException {
        JSONObject json = doWeather(adcode, false);
        checkStatus(json, "实时天气查询");

        JSONArray lives = json.getJSONArray("lives");
        if (lives == null || lives.isEmpty()) {
            return null;
        }
        return lives.getJSONObject(0).to(WeatherLive.class);
    }

    /**
     * 查询指定城市未来 3 天的天气预报
     *
     * @param adcode 城市编码
     * @return 天气预报，若无数据返回 null
     */
    public WeatherForecast queryWeatherForecast(String adcode) throws IOException {
        JSONObject json = doWeather(adcode, true);
        checkStatus(json, "天气预报查询");

        JSONArray forecasts = json.getJSONArray("forecasts");
        if (forecasts == null || forecasts.isEmpty()) {
            return null;
        }
        return forecasts.getJSONObject(0).to(WeatherForecast.class);
    }

    private JSONObject doWeather(String adcode, boolean isForecast) throws IOException {
        String url = HttpUrl.parse(BASE_URL + "/weather/weatherInfo").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("city", adcode)
                .addQueryParameter("extensions", isForecast ? "all" : "base")
                .build().toString();
        return doGet(url);
    }

    // =====================================================================
    // 3. 路径规划（驾车）
    // 文档：https://lbs.amap.com/api/webservice/guide/api/direction
    // =====================================================================

    /**
     * 驾车路径规划
     *
     * @param origin      起点经纬度，格式 "经度,纬度"
     * @param destination 终点经纬度，格式同上
     * @return 驾车路线结果
     */
    public Route drivingRoute(String origin, String destination) throws IOException {
        String url = HttpUrl.parse(BASE_URL + "/direction/driving").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("origin", origin)
                .addQueryParameter("destination", destination)
                .addQueryParameter("extensions", "base")
                .addQueryParameter("strategy", "0")   // 0=速度优先
                .build().toString();
        JSONObject json = doGet(url);
        checkStatus(json, "驾车路径规划");

        JSONObject route = json.getJSONObject("route");
        if (route == null) {
            return null;
        }
        return route.to(Route.class);
    }

    // =====================================================================
    // 通用 GET 请求 & 状态校验
    // =====================================================================

    /** 发送 GET 请求并解析为 JSONObject（供高级用法/调试使用） */
    public JSONObject doGet(String url) throws IOException {
        Request request = new Request.Builder().url(url).get().build();
        try (Response response = httpClient.newCall(request).execute()) {
            if (!response.isSuccessful() || response.body() == null) {
                throw new IOException("请求失败，HTTP 状态码: " + response.code());
            }
            String body = response.body().string();
            return JSON.parseObject(body);
        }
    }

    /** 校验高德业务状态；status != "1" 时抛出异常（T5 会升级为 AmapException） */
    private static void checkStatus(JSONObject json, String apiName) {
        if (json == null) {
            throw new RuntimeException(apiName + " 失败：响应为空");
        }
        String status = json.getString("status");
        if (!STATUS_OK.equals(status)) {
            throw new RuntimeException(apiName + " 失败："
                    + "infocode=" + json.getString("infocode")
                    + ", info=" + json.getString("info"));
        }
    }
}
