import org.example.model.Path;
import org.example.model.Poi;
import org.example.model.Route;
import org.example.model.WeatherLive;

import java.util.List;

/**
 * 高德地图 API 调用示例（POJO 风格）
 */
public class Main {

 /** TODO: 在这里填入你申请的高德 Web 服务 Key */
 private static final String AMAP_KEY = "59d11d17908c9a5ddc8176d78700d6df";

 public static void main(String[] args) {
 AmapClient client = new AmapClient(AMAP_KEY);

 try {
 // ========== 1. POI 搜索：在上海搜索 "肯德基" ==========
