    public ReGeocode regeocode(String location) throws IOException {
        String url = HttpUrl.parse(BASE_URL + "/geocode/regeo").newBuilder()
                .addQueryParameter("key", apiKey)
                .addQueryParameter("location", location)
                .addQueryParameter("extensions", "base")   // base=只返基础地址；all=含周边 POI/道路
                .build().toString();
        JSONObject json = doGet(url);
        checkStatus(json, "逆地理编码");

        JSONObject regeocode = json.getJSONObject("regeocode");
        if (regeocode == null) {
            return null;
        }
        return regeocode.to(ReGeocode.class);
    }

