{"rawEvent":{"message_id":"019daeff1b267fa499fdf8cbde4dd2c5","conversation_id":"019dade4fd787ac38bd21ac6ab930e5b","tool_call_id":"tooluse_aWAkix3rsp4U0tBCMLbRVZ","document":{"file_path":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/web/AmapController.java","sub_content":"AmapController.java","sub_content_event":"open_editor","sub_content_event_value":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/web/AmapController.java","sub_content_tip":"/Users/jiangdadong/CodeBuddy/gaodedemojava01/src/main/java/org/example/web/AmapController.java","apply_content":"package org.example.web;

import org.example.AmapClient;
import org.example.model.Geocode;
import org.example.model.Poi;
import org.example.model.ReGeocode;
import org.example.model.Route;
import org.example.model.WeatherForecast;
import org.example.model.WeatherLive;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.util.List;

/**
 * 高德 API 的 REST 接口层。
 * <p>
 * 所有接口均为 {@code GET}，直接返回高德封装后的 POJO，Spring Boot 会自动用 Jackson 序列化为 JSON。
 * <p>
 * 业务异常 {@link org.example.AmapException} 和 {@link IOException} 由 {@link GlobalExceptionHandler}
 * 统一捕获并返回标准化错误 JSON。
 */
@RestController
@RequestMapping("/api")
public class AmapController {

    private final AmapClient amapClient;

    public AmapController(AmapClient amapClient) {
        this.amapClient = amapClient;
    }

    // =====================================================================
    // 1. POI 搜索
    // =====================================================================

    @GetMapping("/poi")
    public List<Poi> searchPoi(@RequestParam String keywords,
                               @RequestParam(required = false) String city) throws IOException {
        return amapClient.searchPoi(keywords, city);
    }

    // =====================================================================
    // 2. 天气查询
    // =====================================================================

    @GetMapping("/weather/live")
    public WeatherLive weatherLive(@RequestParam String adcode) throws IOException {
        return amapClient.queryWeatherLive(adcode);
    }

    @GetMapping("/weather/forecast")
    public WeatherForecast weatherForecast(@RequestParam String adcode) throws IOException {
        return amapClient.queryWeatherForecast(adcode);
    }

    // =====================================================================
    // 3. 驾车路径规划
    // =====================================================================

    @GetMapping("/route/driving")
    public Route drivingRoute(@RequestParam String origin,
                              @RequestParam String destination) throws IOException {
        return amapClient.drivingRoute(origin, destination);
    }

    // =====================================================================
    // 4. 地理编码 / 逆地理编码
    // =====================================================================

    @GetMapping("/geocode")
    public List<Geocode> geocode(@RequestParam String address,
                                 @RequestParam(required = false) String city) throws IOException {
        return amapClient.geocode(address, city);
    }

    @GetMapping("/regeocode")
    public ReGeocode regeocode(@RequestParam String location) throws IOException {
        return amapClient.regeocode(location);
    }
}
